#!/bin/bash
IFS=. read -r i1 i2 i3 i4 <<< "$1"; mask=$(( 0xFFFFFFFF << (32 - $2) )); ip=$(( (i1 << 24) | (i2 << 16) | (i3 << 8) | i4 )); net=$(( ip & mask )); bc=$(( net | (mask ^ 0xFFFFFFFF) )); printf "%d.%d.%d.%d - %d.%d.%d.%d" $(( ((net+1) >> 24) & 255 )) $(( ((net+1) >> 16) & 255 )) $(( ((net+1) >> 8) & 255 )) $(( (net+1) & 255 )) $(( ((bc-1) >> 24) & 255 )) $(( ((bc-1) >> 16) & 255 )) $(( ((bc-1) >> 8) & 255 )) $(( (bc-1) & 255 ))
